arguments.new_str:
void ApplyMigrations(AppDbContext db)
{
    // EF Core 9 applies each migration in its own transaction;
    // wrapping Migrate() in a manual transaction causes nesting errors.
    var strategy = db.Database.CreateExecutionStrategy();
    strategy.Execute(() => db.Database.Migrate());
}

